// 점프잇=키워드검색×page, 원티드=navigation(직군브라우즈)×page. 키워드는 제목 필터로 좁힘.
const cfg = $input.first().json;
const keywords = cfg.keywords || [];
const maxPages = Math.max(1, Number(cfg.maxPages) || 1);
const cats = cfg.allowedWantedCategories || [518, 507];
const out = [];
// 점프잇: 키워드 검색 (page 페이지네이션 동작)
for (const kw of keywords) {
  const q = encodeURIComponent(kw);
  for (let page = 1; page <= maxPages; page++) {
    out.push({ json: { url: `https://jumpit-api.saramin.co.kr/api/positions?keyword=${q}&sort=relation&page=${page}` } });
  }
}
// 원티드: navigation 직군 브라우즈 (연차/skill_tags 목록에 포함 + offset 페이지네이션 동작)
for (const cat of cats) {
  for (let page = 1; page <= maxPages; page++) {
    const offset = (page - 1) * 20;
    out.push({ json: { url: `https://www.wanted.co.kr/api/chaos/navigation/v1/results?job_group_id=${cat}&country=kr&job_sort=job.latest_order&locations=all&years=-1&limit=20&offset=${offset}` } });
  }
}
return out;

// 정규화 + 제목 키워드 필터 + 연차 필터(수집 단계). 점프잇/원티드 공통.
const stripTags = (s) => (s || '').replace(/<[^>]*>/g, '').trim();
const cfg = $('설정 (Config)').first().json;
const keywords = cfg.keywords || [];
const allowed = cfg.allowedWantedCategories || [518, 507];
const maxYears = Number(cfg.maxCareerYears);

const esc = (s) => s.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
const titleHit = (title) => keywords.some(kw => new RegExp('(^|[^A-Za-z0-9])' + esc(kw) + '([^A-Za-z0-9]|$)', 'i').test(title || ''));
const careerOk = (mc) => !Number.isFinite(maxYears) || mc == null || mc <= maxYears;   // 최소요구경력 <= 상한 (무관=통과)

const out = [];
for (const item of $input.all()) {
  const j = item.json || {};

  const jumpit = j.result?.positions;
  if (Array.isArray(jumpit)) {
    for (const p of jumpit) {
      const title = stripTags(p.title);
      const minCareer = p.minCareer ?? null;
      if (!titleHit(title) || !careerOk(minCareer)) continue;
      out.push({ json: {
        source: 'jumpit', jobId: String(p.id ?? ''),
        company: p.companyName ?? '', title,
        url: `https://jumpit.saramin.co.kr/position/${p.id}`,
        minCareer, maxCareer: p.maxCareer ?? null,
        techStacks: (p.techStacks || []).map(t => stripTags(typeof t === 'string' ? t : (t.stack ?? t.name ?? ''))),
        locations: p.locations ?? [], closedAt: p.closedAt ?? null,
      }});
    }
    continue;
  }

  // 원티드 navigation(data[]) 또는 검색(positions.data[]) 둘 다 지원
  const wanted = j.data ?? j.positions?.data;
  if (Array.isArray(wanted)) {
    for (const p of wanted) {
      const pid = p.category_tag?.parent_id;
      if (allowed.length && pid != null && !allowed.includes(pid)) continue;
      const title = p.position ?? '';
      const minCareer = p.annual_from ?? null;
      let maxCareer = p.annual_to ?? null;
      if (maxCareer != null && maxCareer > 20) maxCareer = null;   // sentinel(100) 정리
      if (!titleHit(title) || !careerOk(minCareer)) continue;
      out.push({ json: {
        source: 'wanted', jobId: String(p.id ?? ''),
        company: p.company?.name ?? '', title,
        url: `https://www.wanted.co.kr/wd/${p.id}`,
        minCareer, maxCareer,
        techStacks: (p.skill_tags || []).map(t => stripTags(typeof t === 'string' ? t : (t.title ?? t.name ?? ''))),
        locations: [], closedAt: p.due_time ?? null,
      }});
    }
    continue;
  }
}
return out;

// 정규화 공고를 pending으로 bulk INSERT하는 SQL 생성 (within-run 중복 제거 + ON CONFLICT).
const esc = (v) => v == null ? 'NULL' : `'${String(v).replace(/'/g, "''")}'`;
const num = (v) => (v == null || v === '') ? 'NULL' : (Number.isFinite(Number(v)) ? Number(v) : 'NULL');
const arr = (list) => { const a = (list || []).map(s => `'${String(s).replace(/'/g, "''")}'`); return a.length ? `ARRAY[${a.join(',')}]::text[]` : `'{}'::text[]`; };
const seen = new Set();
const rows = [];
for (const it of $input.all()) {
  const m = it.json;
  const key = `${m.source}:${m.jobId}`;
  if (!m.jobId || seen.has(key)) continue;   // 이번 실행 내 중복 제거(bulk insert 중복 target 방지)
  seen.add(key);
  rows.push(`(${esc(m.source)},${esc(m.jobId)},${esc(m.company)},${esc(m.title)},${esc(m.url)},${num(m.minCareer)},${num(m.maxCareer)},${arr(m.techStacks)},${esc((m.locations || []).join(', '))},${m.closedAt ? esc(m.closedAt) : 'NULL'})`);
}
if (rows.length === 0) return [];
const sql = `INSERT INTO jobs (source,job_id,company,title,url,min_career,max_career,tech_stacks,locations,closed_at) VALUES ${rows.join(',')} ON CONFLICT (source,job_id) DO NOTHING;`;
return [{ json: { sql, count: rows.length } }];
